// ============================================================
// Node-RED Function node: Dragino RS485-LB decoder
// Eastron SDM630MCT (ML1 / ML4 / RC) → Vlegelbox formaat
//
// AT command volgorde (= volgorde in payload):
// CMD1: 0x0034 PT   total system power W
// CMD2: 0x003C QT   total system VAr
// CMD3: 0x0048      total import kWh
// CMD4: 0x004A      total export kWh
// CMD5: 0x004C      total export kVArh
// CMD6: 0x004E      total import kVArh
// CMD7: 0x003E PFT  total system power factor
// CMD8: 0x0056      max system power demand VA
// ============================================================

const Dev = "ASSET_ID_START_MET_36"; // <-- jouw asset ID

// Volgorde MOET overeenkomen met de AT command volgorde!
const channels = [
    { prop: "total_system_power_W",      id: 4200, scaleBy1000: true  }, // CMD1 slot 0 — W  → kW
    { prop: "total_system_var_VAr",       id: 4300, scaleBy1000: true  }, // CMD2 slot 1 — VAr → kVAr
    { prop: "total_import_kWh",           id: 4600, scaleBy1000: false }, // CMD3 slot 2 — al in kWh
    { prop: "total_export_kWh",           id: 4500, scaleBy1000: false }, // CMD4 slot 3 — al in kWh
    { prop: "total_export_kVArh",         id: 4700, scaleBy1000: false }, // CMD5 slot 4 — al in kVArh
    { prop: "total_import_kVArh",         id: 4800, scaleBy1000: false }, // CMD6 slot 5 — al in kVArh
    { prop: "total_system_power_factor",  id: 4400, scaleBy1000: false }, // CMD7 slot 6 — geen schaling
    { prop: "max_system_power_demand_VA", id: 5700, scaleBy1000: true  }  // CMD8 slot 7 — VA → kVA
];

const HEADER_LEN = 3;

// Decode payload
const buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload;

if (!Buffer.isBuffer(buf) || buf.length < HEADER_LEN + 4) {
    node.error(`Payload te kort: ${buf ? buf.length : 0} bytes`, msg);
    return null;
}

// Batterij uit bytes 0-1 (bit 15 = low battery flag, masken)
const battery = (((buf[0] << 8) | buf[1]) & 0x7FFF) / 1000;

// Float lezen (Big-Endian IEEE754)
function readFloatBE(offset) {
    if (offset + 4 > buf.length) return null;
    const v = buf.readFloatBE(offset);
    return isNaN(v) ? null : Math.round(v * 100) / 100;
}

// MD array opbouwen
const mid = global.get("mid") || 0;
const MD = [];

channels.forEach(function(ch, i) {
    let val = readFloatBE(HEADER_LEN + i * 4);
    if (val === null) return;
    if (ch.scaleBy1000) {
        val = Math.round((val / 1000) * 1000) / 1000;
    }
    MD.push({ Id: ch.id, Val: val });
});

// Batterij
MD.push({ Id: 7200, Val: battery });

// Radio metadata
if (msg.snr  !== undefined) MD.push({ Id: 5400, Val: parseFloat(msg.snr)  });
if (msg.rssi !== undefined) MD.push({ Id: 5500, Val: parseFloat(msg.rssi) });
if (msg.dr?.spreadFactor !== undefined)
    MD.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) });

global.set("mid", mid + 1);

msg.payload = {
    MID: mid,
    D: [{
        Dev: Dev,
        ED:  [],
        MD:  MD,
        TS:  msg.time ? new Date(msg.time).toISOString() : new Date().toISOString()
    }]
};

return msg;
